/// Advance the bookmark to `@-` in both repos.
fn stage_bookmark_both(
    root: &Path,
    state: &PushState,
    params: &PushParams,
) -> Result<(), Box<dyn std::error::Error>> {
    let bk = &state.bookmark;
    let app_arg = root.to_string_lossy();
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if params.dry_run {
        info!(
            "push bookmark-both: [dry-run] would run jj bookmark set {bk} -r @- -R {app_arg} / {claude_arg}"
        );
        return Ok(());
    }
    info!("push bookmark-both: jj bookmark set {bk} -r @- -R {app_arg} / {claude_arg}");
    run(
        "jj",
        &["bookmark", "set", bk, "-r", "@-", "-R", &app_arg],
        root,
    )?;
    run(
        "jj",
        &["bookmark", "set", bk, "-r", "@-", "-R", &claude_arg],
        root,
    )?;
    Ok(())
}

/// Push the app repo's bookmark to origin.
fn stage_push_app(
    root: &Path,
    state: &PushState,
    params: &PushParams,
) -> Result<(), Box<dyn std::error::Error>> {
    let bk = &state.bookmark;
    let app_arg = root.to_string_lossy();
    if params.dry_run {
        info!("push push-app: [dry-run] would run jj git push --bookmark {bk} -R {app_arg}");
        return Ok(());
    }
    info!("push push-app: jj git push --bookmark {bk} -R {app_arg}");
    run(
        "jj",
        &["git", "push", "--bookmark", bk, "-R", &app_arg],
        root,
    )?;
    Ok(())
}

/// Finalize `.claude` via an out-of-process `vc-x1 finalize` call.
/// Shells out rather than calling `finalize::finalize` in-process
/// so `--detach` can fork a child that outlives push's own
/// lifetime. `--no-finalize` turns this stage into a no-op (which
/// is how integration tests avoid spawning a detached process).
fn stage_finalize_claude(
    root: &Path,
    state: &PushState,
    params: &PushParams,
) -> Result<(), Box<dyn std::error::Error>> {
    if params.no_finalize {
        info!("push finalize-claude: skip (--no-finalize)");
        return Ok(());
    }
    let bk = &state.bookmark;
    let claude = claude_path(root);
    let claude_arg = claude.to_string_lossy();
    if params.dry_run {
        info!(
            "push finalize-claude: [dry-run] would run vc-x1 finalize --repo {claude_arg} --squash --push {bk} --delay 10 --detach"
        );
        return Ok(());
    }
    info!(
        "push finalize-claude: vc-x1 finalize --repo {claude_arg} --squash --push {bk} --delay 10 --detach"
    );
    run(
        "vc-x1",
        &[
            "finalize",
            "--repo",
            &claude_arg,
            "--squash",
            "--push",
            bk,
            "--delay",
            "10",
            "--detach",
            "--log",
            "/tmp/vc-x1-finalize.log",
        ],
        root,
    )?;
    Ok(())
}

/// Verify the saved state still matches reality before any stage runs.
///
/// Catches the failure mode where out-of-band activity (manual finalize,
/// squash + force-push, abandon, etc.) moved the world forward between
/// the prior push and this resume, leaving `state` pointing at a
/// now-bogus halt point. The 0.37.1 dogfood incident is the canonical
/// example: push parked at `finalize-claude` after a failure; manual
/// recovery moved the world forward; the next push resumed at the
/// parked stage, no-op'd, and falsely declared "completed all stages"
/// while working copies still held uncommitted changes.
///
/// Three checks (per chores-06 [61] design):
///

}

/// Reposition `@` onto the freshly-synced bookmark after a successful
/// sync.
///
/// Dispatches on repo role — the caller has already excluded the
/// deprecated verify-only mode:
///
/// - **session (bot) sub-repo** → always `jj new main`
///   (see `reposition_session`).
/// - **any other repo** → move `@` onto the synced `bookmark` under
///   the code-repo safety rules (see `reposition_code`).
fn reposition_at(
    repo: &Path,
    bookmark: &str,
    params: &SyncParams,
) -> Result<(), Box<dyn std::error::Error>> {
    if is_session_repo(repo) {
        reposition_session(repo)
    } else {
        reposition_code(repo, bookmark, params.rebase)
    }
}

/// True when `repo` is the session (bot) sub-repo.
///
/// Reads `<repo>/.vc-config.toml`'s `[workspace] path`: the code repo
/// (workspace root) is `"/"`, the session sub-repo is `"/.claude"`. A
/// missing / unreadable config (POR, single-repo workspace) is treated
/// as a code repo.
fn is_session_repo(repo: &Path) -> bool {
    match toml_simple::toml_load(&repo.join(VC_CONFIG_FILE)) {
        Ok(cfg) => {
            toml_simple::toml_get(&cfg, "workspace.path").map(String::as_str) == Some("/.claude")
        }
        Err(_) => false,
    }
}

/// Reposition the session repo's `@` onto `main`.
///
/// The session (`.claude`) repo is a linear journal on `main`, and its
/// `@` normally carries live session writes:
///
/// - Errors when `@-` isn't on `main` (not an ancestor-or-equal of the
///   bookmark) — refuse rather than guess.
/// - Otherwise `jj new main` starts a fresh `@` on the bookmark; the
///   prior `@` becomes a sibling head, which is expected for the
///   journal. A conflict is very unlikely given `.claude`'s content;
///   if one ever appears the user resolves it.
fn reposition_session(repo: &Path) -> Result<(), Box<dyn std::error::Error>> {
    let parent = commit_id(repo, "@-")?;
    if !revset_nonempty(repo, &format!("{parent}::main"))? {
        return Err(format!(
            "{}: @- ({parent}) is not on main — refusing to reposition @",
            repo.display()
        )
        .into());
    }
    info!("{}: jj new main", repo.display());
    run(
        "jj",
        &["new", "main", "-R", &repo_str(repo)],
        Path::new("."),
    )?;
    Ok(())
}

/// Reposition the code repo's `@` onto the synced `bookmark`.
///
/// Let `@-` be the parent of `@`:
///
/// - `bookmark == @-` → already positioned; no-op.
/// - `bookmark` a proper descendant of `@-`, `@` empty →
///   `jj new bookmark` (jj auto-abandons the old empty `@`).

